## 3. Pybind11 binding code (the *glue*)

```cpp
// ------------------------------------------------------------
// file: pcapng_bindings.cpp
// ------------------------------------------------------------
#define PY_SSIZE_T_CLEAN
#include <pybind11/pybind11.h>
#include <pybind11/stl.h>          // automatic conversion of std::vector, std::string …
#include <pybind11/chrono.h>       // conversion of std::chrono::system_clock::time_point
#include <pybind11/functional.h>   // conversion of std::function / any callable

#include "libpcapng_stub.hpp"

namespace py = pybind11;
using namespace libpcapng;

PYBIND11_MODULE(pcapng, m) {
    m.doc() = R"pbdoc(
        Python bindings for a tiny libpcapng‑style parser.

        The module provides two public classes:

        * **Reader** – opens a pcapng file and acts as an iterator over :class:`Frame`.
        * **Frame**  – a lightweight view of a captured packet.

        Typical usage:

        >>> import pcapng
        >>> rdr = pcapng.Reader("sample.pcapng")
        >>> for frm in rdr:
        ...     print(frm.timestamp, frm.len)

        Or, if you want the heavy lifting to stay in C++:

        >>> def my_cb(frame):
        ...     print("got", frame.len)
        >>> rdr.for_each(my_cb)
    )pbdoc";

    // ------------------------------------------------------------------
    // Frame
    // ------------------------------------------------------------------
    py::class_<Frame>(m, "Frame", R"pbdoc(
        A single packet/frame extracted from a pcapng capture.

        Attributes
        ----------
        timestamp : datetime.datetime
            The capture timestamp (UTC) of the frame.
        len : int
            Length of the raw packet data (in bytes).
        data : bytes
            The raw packet bytes.
    )pbdoc")
        .def_property_readonly("timestamp",
            [](const Frame& self) -> py::datetime {
                // pybind11::datetime expects a tz‑aware datetime; we give UTC.
                using namespace std::chrono;
                auto tp = self.timestamp();
                auto secs = time_point_cast<std::seconds>(tp);
                auto nanos = duration_cast<std::nanoseconds>(tp - secs).count();
                std::time_t tt = system_clock::to_time_t(secs);
                std::tm utc_tm = *std::gmtime(&tt);
                return py::datetime(utc_tm.tm_year + 1900,
                                    utc_tm.tm_mon  + 1,
                                    utc_tm.tm_mday,
                                    utc_tm.tm_hour,
                                    utc_tm.tm_min,
                                    utc_tm.tm_sec,
                                    static_cast<int>(nanos / 1000));
            },
            "Capture timestamp (UTC).")
        .def_property_readonly("len",
            [](const Frame& self) { return self.len(); },
            "Length of the packet data (bytes).")
        .def_property_readonly("data",
            [](const Frame& self) { return py::bytes(reinterpret_cast<const char*>(self.data().data()),
                                                     self.data().size()); },
            "Raw packet bytes.")
        .def("__repr__",
            [](const Frame& self) {
                return "<pcapng.Frame len=" + std::to_string(self.len()) + ">";
            });

    // ------------------------------------------------------------------
    // Reader – iterator protocol
    // ------------------------------------------------------------------
    py::class_<Reader>(m, "Reader", R"pbdoc(
        Opens a pcapng file and provides an iterator over :class:`Frame`.

        Parameters
        ----------
        filename : str
            Path to a pcapng file.

        Notes
        -----
        The iterator is *forward‑only* – you cannot rewind it without creating a
        new ``Reader`` instance.
    )pbdoc")
        .def(py::init<const std::string&>(),
             py::arg("filename"),
             "Open a pcapng file for reading.")
        // ---- iterator protocol -------------------------------------------------
        .def("__iter__", [](const Reader& self) { return py::make_iterator(self.begin(), self.end()); },
             py::keep_alive<0, 1>(), // iterator keeps Reader alive
             "Return an iterator over frames.")
        // ---- callback helper ----------------------------------------------------
        .def("for_each",
            [](const Reader& self, py::function py_cb) {
                // Release the GIL for the whole iteration; reacquire only for the callback.
                py::gil_scoped_release release;
                self.for_each([&](const Frame& f) {
                    // The lambda runs with the GIL *acquired* (see for_each implementation)
                    py_cb(f);
                });
            },
            py::arg("callback"),
            R"pbdoc(
                Call *callback* for each frame in the capture.

                The iteration runs on the C++ side (so it is fast), but the GIL is
                reacquired for each call to *callback*.  The callback receives a
                :class:`Frame` instance.

                Example
                -------
                >>> def printer(frame):
                ...     print(frame.timestamp, frame.len)
                >>> rdr.for_each(printer)
            )pbdoc")
        .def("__repr__",
            [](const Reader& self) { return "<pcapng.Reader>"; });
}
```

### What the binding does

| Feature | Implementation detail |
|---------|------------------------|
| **Python class `Frame`** | Wrapped directly; `timestamp` is converted to a `datetime.datetime` (UTC). `data` is exposed as a Python `bytes` object. |
| **Python class `Reader`** | Exposes a constructor that takes a filename. |
| **Iterator protocol** | `Reader.__iter__` returns a *pybind11* iterator (`py::make_iterator`) that walks the underlying C++ iterator (`Reader::begin/end`). The iterator keeps the `Reader` object alive (`keep_alive<0,1>`). |
| **Callback style (`for_each`)** | The binding releases the GIL for the whole iteration (`py::gil_scoped_release`). Inside `Reader::for_each` the GIL is reacquired *just* before invoking the Python callable (`py::gil_scoped_acquire`). This gives the best of both worlds: minimal Python overhead while still letting the user run arbitrary Python code per‑frame. |
| **Error handling** | Any C++ exception (e.g. `std::runtime_error` from a missing file) is automatically translated into a Python `RuntimeError`. |
| **Memory safety** | All objects are owned by C++ (`Reader` owns its internal `std::vector<Frame>`). The iterator keeps the parent alive, and the `for_each` lambda captures the Python callable by reference (the GIL‑acquire ensures the reference stays valid). |

