## 4. Build system (CMake)

```cmake
# ------------------------------------------------------------
# file: CMakeLists.txt
# ------------------------------------------------------------
cmake_minimum_required(VERSION 3.14)
project(pcapng_bindings LANGUAGES CXX)

# ---- pybind11 -------------------------------------------------
# You can either fetch pybind11 via FetchContent or assume it is installed.
include(FetchContent)
FetchContent_Declare(
    pybind11
    GIT_REPOSITORY https://github.com/pybind/pybind11.git
    GIT_TAG        v2.11.1   # or the latest stable tag
)
FetchContent_MakeAvailable(pybind11)

# ---- Build the module -----------------------------------------
add_library(pcapng MODULE
    pcapng_bindings.cpp
    libpcapng_stub.hpp   # header‑only stub – no .cpp needed
)

target_include_directories(pcapng PRIVATE ${CMAKE_CURRENT_SOURCE_DIR})
target_compile_features(pcapng PRIVATE cxx_std_17)

# pybind11 adds the proper compile definitions and links.
target_link_libraries(pcapng PRIVATE pybind11::module)

# The extension is a Python module – the suffix is platform‑specific.
set_target_properties(pcapng PROPERTIES
    PREFIX "${PYTHON_MODULE_PREFIX}"
    SUFFIX "${PYTHON_MODULE_EXTENSION}"
)
```

**How to build**

```bash
mkdir build && cd build
cmake .. -DPython3_EXECUTABLE=$(which python3)
cmake --build .
```

The resulting file (`pcapng.cpython-311-x86_64-linux-gnu.so` on Linux, for example) can be copied next to a test script or installed with `pip install .` (add a minimal `setup.py` if you need a proper wheel).

---

## 5. Full example script (how a Python user would use the API)

```python
# ------------------------------------------------------------
# file: demo.py
# ------------------------------------------------------------
import pathlib
import pcapng

def print_summary():
    # Open a (fake) pcapng file – the stub just splits the file into 1500‑byte chunks.
    rdr = pcapng.Reader(str(pathlib.Path(__file__).with_name("sample.pcapng")))

    # ------------------------------------------------------------------
    # 1️⃣  Classic Python iteration – easy, but incurs Python overhead per frame.
    # ------------------------------------------------------------------
    print("=== Python‑level iteration ===")
    for frm in rdr:
        print(f"frame @ {frm.timestamp.isoformat()} – {frm.len} bytes")

    # ------------------------------------------------------------------
    # 2️⃣  Callback style – the heavy loop stays in C++.
    # ------------------------------------------------------------------
    print("\n=== C++‑driven callback ===")
    total_bytes = 0

    def accumulate(frame):
        nonlocal total_bytes
        total_bytes += frame.len

    rdr.for_each(accumulate)
    print(f"Total bytes in the capture: {total_bytes}")

if __name__ == "__main__":
    print_summary()
```

Running the demo (assuming you have a `sample.pcapng` file in the same directory) yields something like:

```
=== Python‑level iteration ===
frame @ 2024-10-14 12:34:56.123456+00:00 – 1500 bytes
frame @ 2024-10-14 12:34:56.124456+00:00 – 1500 bytes
...

=== C++‑driven callback ===
Total bytes in the capture: 4500
```

